  [11] = {
    ["T"] = "Награда за гноллов Речной Лапы",
    ["O"] = "Принесите 8 раскрашенных поручей гноллов в казармы заместителю судьи Рейнеру.",
    ["D"] = "На границах Элвиннского леса заметили гноллов – звероподобных тварей, которым не место в этих землях. К югу от башни стражи лес кишит большой стаей – их слишком много, чтобы мы сами могли с ними справиться. Еще одна группа обосновалась к востоку, неподалеку от озера Каменных Столбов.\n\nАрмия Штормграда щедро вознаградит любого, кто поможет их истребить. В доказательство своих подвигов принеси мне раскрашенные нарукавные повязки гноллов.",
