  [8960] = {
    ["T"] = "Несчастливая судьба Бодли",
    ["O"] = "Отправляйтесь в Черную гору и используйте Экстра-пространственный проявитель призраков, чтобы найти Бодли возле Верхней Черной горы.",
    ["D"] = "Значит, нам нужно восстановить остальную часть медальона? Найти Бодли будет непросто. Он вернулся на Черную гору, чтобы попытаться снова войти в Верхнюю Черную гору, и не вернулся.\n\nЯ бы посоветовал взять с собой проявитель призраков гоблина, так как я опасаюсь худшего.",
  },
  [8961] = {
    ["T"] = "Два короля пламени",
    ["O"] = "Добудьте Инцендицит Инцендиуса и Искру Искрохранителя, а также Освященную жаровню, и отнесите их Бодли внутри Черной горы.",
    ["D"] = "Чтобы призвать лорда Валталака, нам сначала нужно собрать две другие трети амулета. Для этого нам понадобится жаровня и особые угли, чтобы в ней горело.\n\nЕсть два повелителя огня: лорд Инцендиус в Глубинах Черной горы и Пирос-страж Искрохранитель в Верхней Черной горе. У них есть то, что нам нужно. Добудьте у каждого частицу их останков, а затем вернитесь ко мне с Освященной жаровней, которую можно купить у Алого ордена, если вы пользуетесь его расположением.",
  },
  [8962] = {
    ["T"] = "Важные компоненты",
    ["O"] = "Добудьте Останки друида и верните их Бодли внутри Черной горы.",
    ["D"] = "$C, слушай внимательно. Теперь, когда у нас есть жаровня и чем ее зажечь, нам все еще нужен еще один компонент, чтобы наполнить ее энергией; что-то, что создаст фокус, достаточно сильный, чтобы привлечь дух моего покойного бывшего товарища.\n\nМор Седогрив, наш самый выдающийся друид, имел много близких друзей в Круг Кенария. Он участвовал в экспедиции в Азшару для изучения обитающих там каменных великанов, но те были слишком агрессивны, и большинство участников экспедиции погибло. Мне нужно, чтобы ты достал Останки друида у этих великанов на северо-востоке Азшары.",
  },
  [8963] = {
    ["T"] = "Важные компоненты",
    ["O"] = "Добудьте Реликвию деревни Звездный Ветер и верните ее Бодли внутри Черной горы.",
    ["D"] = "$C, слушай внимательно. Теперь, когда у нас есть жаровня и чем ее зажечь, нам все еще нужен еще один компонент, чтобы наполнить ее энергией; что-то, что создаст фокус, достаточно сильный, чтобы привлечь дух моего покойного бывшего товарища.\n\nИсалиен, наша жрица, выросла в Зимнем Ключе, в деревне Звездный Ветер. Мне нужно, чтобы ты добыл Реликвию деревни Звездный Ветер у великанов Морозного Молота из ущелья Ледяного Шепота на юге Зимнего Ключа, которые время от времени совершают набеги на север.",
  },
  [8964] = {
    ["T"] = "Важные компоненты",
    ["O"] = "Добудьте Сияющий меч фанатизма и верните его Бодли внутри Черной горы.",
    ["D"] = "$C, слушай внимательно. Теперь, когда у нас есть жаровня и чем ее зажечь, нам все еще нужен еще один компонент, чтобы наполнить ее энергией; что-то, что создаст фокус, достаточно сильный, чтобы призвать души моих покойных бывших товарищей.\n\nБратья Джариен и Сотос верили в путь Алого ордена. Они стремились к рыцарству в этой гнусной организации. Отправляйся в Руку Тира в Восточных Чумных землях и добудь Сияющий меч фанатизма у тамошних преторианцев.",
  },
  [8965] = {
    ["T"] = "Важные компоненты",
    ["O"] = "Добудьте Пепел душ Изгнанных и верните их Бодли внутри Черной горы.",
    ["D"] = "$C, слушай внимательно. Теперь, когда у нас есть жаровня и чем ее зажечь, нам все еще нужен еще один компонент, чтобы наполнить ее энергией; что-то, что создаст фокус, достаточно сильный, чтобы привлечь дух моего покойного бывшего товарища.\n\nОгр-некромант, путешествовавший с нами, Кормок, любил призывать души изгнанных мертвецов с острова Чистилище, у южного побережья Предгорий Хилсбрада. Отправляйся туда и добудь немного Пепла душ Изгнанных из их останков.",
  },
  [8966] = {
    ["T"] = "Левая часть амулета лорда Валталака",
    ["O"] = "Используйте Жаровню призыва, чтобы вызвать дух Мора Седогрива и убить его. Вернитесь к Бодли внутри Черной горы с Левой частью амулета лорда Валталака и Жаровней призыва.",
    ["D"] = "Мой друг Мор Седогрив первым пал жертвой обладания частью амулета лорда Валталака и содержащимся в нем осколком духа. После того как мы украли книгу заклинаний и амулет Валталака, мы бежали, спасая свои жизни, из верхней части Верхней Черной горы. По пути Мор упал в нижнюю часть горы.\n\nПозже мы обнаружили, что он выжил после падения, но был схвачен и подвергнут пыткам военным мастером Вуном. Несколько духов-убийц пробрались и убили его прямо на глазах у Вуна.",
  },
  [8967] = {
    ["T"] = "Левая часть амулета лорда Валталака",
    ["O"] = "Используйте Жаровню призыва, чтобы вызвать дух Исалиен и убить ее. Вернитесь к Бодли внутри Черной горы с Левой частью амулета лорда Валталака и Жаровней призыва.",
    ["D"] = "Позже мы узнали, когда пытались выжить сами, что Исалиен, ночная эльфийка-жрица из нашей компании, отправилась в человеческую тюрьму на Тол Бараде, чтобы навестить своего заключенного друга Фалрина Тришапера.\n\nОднако до目的地 она не добралась. До нас дошли слухи, что на нее напали в зале ожидания Духи-убийцы, посланные, без сомнения, лордом Валталаком. Теперь в этом зале ожидания содержится могущественный маг.",
  },
  [8968] = {
