  [9610] = {
    ["T"] = "Озеро Слез",
    ["O"] = "Добудьте 10 артефактов Атал'ай и вернитесь Финмиру в Убежище в Болоте Печали.",
    ["D"] = "Меня интересует изучение прошлого Азерота, и мне интересно, не согласишься ли ты помочь?\nНеподалеку в болоте есть место, имеющее историческое значение, куда я хотел бы тебя отправить. Озеро Слез находится к юго-востоку. Говорят, что на его берегах и в глубинах похоронены артефакты тролльей цивилизации Атал'ай.\nНо будь осторожен: его охраняют древний зеленый дракон Сомнус и его дракониды, а также плотоядные рыбы в самом озере!",
  },
  [11160] = {
    ["T"] = "Знамя Камнемолота",
    ["O"] = "Верните Знамя Камнемолота и принесите его Броггу в Логово Брогга.",
    ["D"] = "Когда пришли драконы и захватили старый дом Брогга, огры Камнемолота бежали, бросив всё, включая знамя клана.\nБрогг знает, что знамя хранилось глубоко в кургане огров Камнемолота, но теперь это место называется Логово Пламени. Броггу нужно знамя клана, чтобы отомстить драконам, убившим его друзей.\nСтарый курган клана Брогга, Логово Пламени, находится к северу от моего убежища и кишит драконидами. Знамя будет глубоко внутри пещеры. Будь осторожен, $N.",
