  [26100] = {
    ["T"] = "Кроколиски в городе",
    ["O"] = "Поймайте Детеныша кроколиска в Оргриммаре и вернитесь к Старику Барло в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Здравствуй, $C. Я рад, что ты зашел поболтать к этому старику — у нас тут неприятности.\n\nКакой-то странствующий торговец недавно продал партию детенышей кроколисков доверчивым детишкам. Кроколиски — дикие звери, и многие из них сбежали и теперь прячутся в городских каналах.\n\nВозьми свою самую крепкую удочку, закинь ее в любом крупном городе и принеси одного из маленьких дьяволов мне. Мне не терпится на него взглянуть.",
  },
  [26101] = {
    ["T"] = "Лунная рыба Луносвета",
    ["O"] = "Поймайте 10 Лунных рыб в Луносвете и вернитесь Вифле в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Если ищешь спокойное место для рыбалки, тебе не найти места лучше, чем Луносвет. Более спокойных вод ты не найдешь во всей Калимдоре.\n\nЯ задолжал своей подруге Вифле рыбу по одному проигранному пари, но у меня не было времени сходить в Луносвет за ней. Может быть, ты захочешь наловить ее для меня? Ты окажешь этому старику большую услугу.",
  },
  [26102] = {
    ["T"] = "Призраки в реке",
    ["O"] = "Поймайте Призрачную рыбу в Мертвом ущелье и вернитесь Орсоохе в Деревню Черной Лапы в Азшаре.",
    ["D"] = "В былые времена рыбалка вокруг старой Каражан была бойкой и славной. Затем начались все эти неприятности с Легионом, демонами и уходом Медива. Это место заставляет мои старые кости дрожать.\n\nМой друг Орсооха был любопытен, можно ли там еще ловить рыбу. Мне было слишком стыдно признаться, что я боюсь, но я согласился попробовать. Не могу заставить себя выбраться туда — суеверие, как у большинства рыбаков.\n\nМожет быть, ты согласишься проверить это место и принести то, что клюет для него?",
  },
  [26103] = {
    ["T"] = "Замороженные припасы",
    ["O"] = "Соберите 10 Замороженных шариков в Зимнем Ключе и вернитесь Вифле в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Знаешь, рыбалка хороша не только тем, что с ее помощью можно поймать себе обед. Она еще может помочь тебе в жаркий летний день.\n\nВозьми, к примеру, воды Зимнего Ключа: ты можешь выудить большие глыбы льда, которые сохраняются днями — они замерзают так сильно. Отлично подходят для хранения рыбы во время транспортировки или чтобы запустить в кого-нибудь, когда на тебя странно смотрят.\n\nВообще-то, у меня они почти закончились. Не хочешь пополнить наши запасы? Когда закончишь, отнеси их Вифле.",
  },
  [26104] = {
    ["T"] = "Рыбалка ради прекрасного",
    ["O"] = "Поймайте Прекрасный пейзаж в Восточных Чумных землях и вернитесь Орсоохе в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Знаешь, в мире есть много вещей, которые попадают в реки, озера и океаны. Некоторые из них даже чего-то стоят!\n\nВозьми, к примеру, ремесленные изделия и предметы искусства, которые выходили с мельницы Броумана в том месте, что теперь называется Восточные Чумные земли. Там были поистине прекрасные вещи, великолепные пейзажи и причудливые деревянные скульптуры, которые бы понравились Орсоохе. Может быть, некоторые из них смыло в то, что осталось от тамошних озер. Стоит проверить, а?",
  },
  [26105] = {
    ["T"] = "Целеустремленная тумпа",
    ["O"] = "Поймайте 10 Тумп в Западных Чумных землях и вернитесь Вифле в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Река Торидал, впадающая в озеро Дэрроумир в том месте, что теперь называется Западные Чумные земли, всегда была трудной для рыбалки. Слишком трудной сейчас для этих старых костей, это уж точно.\n\nЕсли ищешь испытание, ты можешь выловить улов Тумп в этих водах. Уверен, Вифле будет весьма впечатлена. Просто, следи за тамошними молотильщиками в озере. Я слышал, они теперь все чумные.",
  },
  [26106] = {
    ["T"] = "Омары, не боящиеся лавы",
    ["O"] = "Поймайте 10 Омаров, не боящихся лавы, в Горящих степях и вернитесь Орсоохе в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Ах, Горящие степи... запах серы и пива. Пробуждает отличное настроение, чтобы взять удочку и выйти на охоту. Там только лава, но ты все равно можешь наловить себе пиршество. Я говорю о знаменитых омарах, не боящихся лавы. Панцирь крепкий, как гвозди, и устойчивый к огню, но как только его снимешь, о! Острый, пряный вкус внутри не сравним ни с чем.\n\nУ Орсоохи есть клешни, чтобы разделать их, так что отнеси их ему, когда наберешь достаточно, чтобы поделиться.",
  },
  [26107] = {
    ["T"] = "Eau de Parfish",
    ["O"] = "Поймайте Ароматную рыбу Скверны в Проклятом лесу и вернитесь Вифле в Деревне Черной Лапы в Азшаре.",
    ["D"] = "Я никогда не пойму моду, $N. Особенно моду фурболгов. Вифле говорит мне, что Черная Лапа делает одеколон из рыбы, которую они раньше добывали в том месте, что теперь называется Проклятый лес. Вонючая!\n\nНо если это важно для наших пушистых друзей здесь, то это важно и для меня. Мне интересно, можем ли мы все еще получить этого ароматного зверя, даже после того, как воды были осквернены скверной. Готов попробовать?",
  },
  [26108] = {
    ["T"] = "Необузданный Ун'Горо",
    ["O"] = "Поймайте 10 Огненных шипозубов в кратере Ун'Горо и вернитесь Орсоохе в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Мало мест в мире, где я не ловил рыбу, но одно из них — это дикие земли кратера Ун'Горо. Если бы эти старые кости могли пережить спуск, я бы с радостью занялся своим ремеслом в необузданных водах кратера. Увы, мне придется положиться на таких молодых, как ты.\n\nОрсооха отлично умеет обращаться с экзотической рыбой. Может быть, ты принесешь нам десять штук, и мы все через тебя сможем насладиться трапезой?",
  },
  [26109] = {
    ["T"] = "Орки и их чрезмерный вылов рыбы",
    ["O"] = "Поймайте 10 Оранжевых большеголовов в Выжженных землях и вернитесь Вифле в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Орки, верные Легиону, которые кишат в Крепости Камня Скверны в Выжженных землях, вылавливают близлежащее побережье досуха, чтобы прокормить свою ненасытную армию демонов. Мы должны действовать, чтобы сохранить несколько прекрасных Оранжевых большеголовов, которые населяют те берега!\n\nВылови десять штук, а затем отнеси их Вифле. Она позаботится, чтобы они жили в мире здесь, чтобы мы могли в конечном итоге выпустить их снова, как только эти орки будут повержены.",
  },
  [26110] = {
    ["T"] = "Самая редкая из всех",
    ["O"] = "Поймайте Сапфирового дротика в Азшаре и вернитесь Орсоохе в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Ах, Азшара. Дом вдали от дома для меня и дом для моих друзей. Здесь так много мест для рыбалки, что ты всегда можешь найти новое любимое.\n\nЯ провел больше времени за рыбалкой в Азшаре, чем где-либо еще, но есть один улов, который ускользает от меня: Сапфировый дротик. Когда фурболги ловят одного, он попадает на их стену трофеев, а не в похлебку! Может, попробуешь поймать одного сам? Он может быть где угодно...!",
  },
  [26111] = {
    ["T"] = "Кража карманных часов",
    ["O"] = "Достаньте Карманные часы Барло в Пылающем ущелье и вернитесь Вифле в Деревню Черной Лапы в Азшаре.",
    ["D"] = "О господи, $C, я в ужасном состоянии. Я только что вернулся из поездки на лавовые озера Пылающего ущелья и не могу найти свои счастливые карманные часы!\n\nЭтим старым костям нужно немного отдохнуть, прежде чем снова отправиться в путь, но если я буду ждать слишком долго, лава расплавит мои часы в жидкую пасту, как только магия рассеется. Может быть, ты сможешь прыгнуть туда и выловить их для меня? Вифла почистит их, если ты сможешь их вернуть.",
  },
  [26112] = {
    ["T"] = "Троллья форель",
    ["O"] = "Поймайте 10 Длинных форелей в Танарисе и вернитесь Орсоохе в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Тролли в Анье'Вата скрещивают пресноводную форель с морским окунем, чтобы создать новый вид рыбы, известный как 'лан'гва' или 'Длинная форель' на Общем языке. Прошло некоторое время с тех пор, как мы пробовали ее на вкус. Почему бы тебе не отправиться в Танарис и не посмотреть, что ты сможешь поймать?",
  },
  [26113] = {
    ["T"] = "Сказочная рыбалка",
    ["O"] = "Поймайте 10 Окуней золотой чешуи во Внутренних землях и вернитесь Вифле в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Присядь, $C, и я расскажу тебе историю.\n\nДавным-давно во Внутренних землях жили высокие эльфы, которые не умели рыбачить. Так вот, я ввязался в переделку с троллями Пустокорых, в подробности я вдаваться не буду, но в обмен на мое спасение я научил их рыбачить, и им это понравилось! Или они мне так сказали.\n\nПозже оказалось, что они меня просто разыгрывали. Вроде как с тех пор держался подальше от этого места, но если ты не против отправиться туда, Вифла очень хочет отведать Окуней золотой чешуи.",
  },
  [26114] = {
    ["T"] = "Рыбалка на Перьевой Луне",
    ["O"] = "Поймайте Синеспинного марлина в Фераласе и вернитесь Орсоохе в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Остров Перьевой Луны довольно удаленное место для рыбалки, но если найти правильное место, рыба там клюет отлично.\n\nЕсли хочешь испытать свои силы против лучшего, что может предложить океан, найди Синеспинного марлина. Они устроят тебе чертовски тяжелую борьбу, пытаясь вытащить их, но о, какое филе можно получить даже от одной! Орсооха поможет тебе с этой частью.",
