  [26115] = {
    ["T"] = "Вылавливая мурлоков",
    ["O"] = "Поймайте 10 Плоских рыб Грязнорыла в Болоте Печали и вернитесь Вифле в Деревню Черной Лапы в Азшаре.",
    ["D"] = "Эй, $C! Мои старые кости скрипят от рыбацких историй прошлых дней, и у меня есть для тебя предложение. Мутные воды Болота Печали кишат всевозможными скользкими тварями, которых так любит Вифла, и я думаю, пришло время закинуть удочки и посмотреть, что мы сможем выловить. Но будь осторожен, болото водится не только рыбой. Под этими мрачными глубинами скрываются опасности, так что будь начеку.",
  },
  [26116] = {
    ["T"] = "Просеивая песок",
