  [26498] = {
    ["T"] = "Цветы для Эллисон",
    ["O"] = "Соберите 8 ледяных чертополохов в Альтеракских горах и положите их на могилу Эллисон Мон Клер на кладбище Южнобережья.",
    ["D"] = "Привет, незнакомец. Ты направляешься в Южнобережье? Если так, не мог бы ты оказать мне услугу?\n\nДо войны я любил девушку по имени Эллисон Мон Клер. Затем я ушел в море, и пришла Плеть. Когда я вернулся домой, я нашел Эллисон. Она похоронена на кладбище Южнобережья.\n\nУ меня не хватает духу снова навестить ее могилу, но я хочу почтить ее память. Если ты согласишься собрать немного ледяного чертополоха в Альтеракских горах и положить их на ее могилу, я буду благодарен.",
  },
  [26499] = {
    ["T"] = "Магический материал",
    ["O"] = "Поговорите с даларанскими призывателями, чтобы получить Руны открытия, затем используйте их, чтобы открыть магически запечатанные прочные сундуки в Даларане, и соберите находящийся внутри Магический материал. Принесите 30 Магического материала архимагу Ансирему Руновидцу возле Даларана в Альтеракских горах.",
    ["D"] = "Итак, ты хочешь нам помочь? Я как раз знаю, что нужно!\n\nКак видишь, за пределами магического купола, который мы воздвигли вокруг Даларана, есть руины. Внутри некоторых руин ты найдешь магически запечатанные контейнеры. Волшебные замки этих контейнеров можно открыть с помощью Руны открытия.\n\nЯ хочу, чтобы ты поговорил с даларанскими призывателями в этом районе и попросил у них одолжить Руны открытия. Затем обыщи сундуки и собери находящийся внутри Магический материал. Будь осторожен — некоторые сундуки могут быть зачарованы заклинанием, которое призовет стража.",
