  [26500] = {
    ["T"] = "Странный фолиант",
    ["O"] = "Принесите Некромантический фолиант Уэнделу Спаркбрайту в гавани Штормграда.",
    ["D"] = "В куче вещей, которые ты собрал, я заметил вызывающий беспокойство предмет. Это фолиант некромантии, запретной магии, практика которой привела к падению нашего города и Лордерона. Думаю, ты не помнишь, из какого дома ты взял этот фолиант...?\n\nК счастью для нас, на этом фолианте стоит читательская печать. Я знаю, ты устал слушать о печатях и магических защитах, но имей терпение еще раз выслушать объяснение. Эта печать перемешивает буквы в фолианте для всех, кроме предназначенного читателя. Мы можем определить, кто наложил эту печать, и таким образом, кому принадлежал этот фолиант.\n\nОтнеси этот фолиант Уэнделу Спаркбрайту в Штормграде. Он любит тусоваться в гавани, у самых южных доков.",
  },
  [26501] = {
    ["T"] = "Странный фолиант",
    ["O"] = "Верните Некромантический фолиант архимагу Ансирему Руновидцу возле Даларана в Альтеракских горах.",
    ["D"] = "Бум бам блам! Вот так просто! Ты ожидал, что мне понадобится магический реагент, который редко можно найти только в подмышке мурлока? Нет! Это действительно очень простое заклинание. Честно! Этот фолиант был не очень хорошо защищен.\n\nВ любом случае, этот фолиант принадлежал некоему Арману Ненстоку! Понятия не имею, кто это. Надеюсь, архимаг знает. Отнеси его обратно ему и передай от меня привет.",
  },
  [26502] = {
    ["T"] = "Редкие книги",
    ["O"] = "Убейте Тарга и Гломмуса в руинах Альтерака и заберите все книги, которые могут быть у них. Затем вернитесь к летописцу Диббсу в Южнобережье.",
    ["D"] = "Королевство Альтерак не было известно своими научными исследованиями, но в библиотеке Альтерак-Сити было несколько редких фолиантов. Теперь, когда огры захватили руины города, интересно, можно ли эти фолианты достать...\n\nОгры любят собирать книги, которые считают ценными, даже если сами не умеют читать. Лидеры огров собирали бы книги с позолоченным переплетом — особенно те, которые были иллюминированы красивыми картинками. Их убийство может позволить нам найти несколько из этих потерянных сокровищ.",
  },
  [26503] = {
