  [26515] = {
    ["T"] = "Наследие Перенольдов",
    ["O"] = "Возьмите перстень генерала Хата на кладбище возле Лагеря Пронизывающего Ветра и похороните его вместе с Айденом Перенольдом.",
    ["D"] = "Итак, Алиден Перенольд мертв, и он хотел, чтобы генерал Хат знал об этом? Интересно, почему?\n\nЯ тот, кого ты ищешь, $C.\n\nЯ расстался с Перенольдами в плохих отношениях, и эти чувства никогда не уходили. Я просто хочу прожить остаток своей жизни в мире. Как однажды сказал Троллбайн, предательство невозможно простить.\n\nПоскольку ты, кажется, любишь выполнять чужие поручения, у меня есть еще одно задание для тебя. Возьми этот перстень с печаткой, мою последнюю реликвию тех дней, и похорони его на могиле короля Айдена на кладбище возле Лагеря Пронизывающего Ветра, прямо через границу от Альтерака. Затем давай больше никогда не будем говорить о Перенольдах.",
  },
  [26516] = {
