  },
  [26524] = {
    ["T"] = "В поместье Темного Когтя",
    ["O"] = "Принесите Заколдованный пергамент лорду Джораху Темному Когтю в Поместье Темного Когтя в Альтеракских горах.",
    ["D"] = "Тьфу! Что это? Тайная магия! Я ничего не могу с этим поделать.\n\nЕсли у Нагаза был этот пергамент, мы должны понять, что в нем написано. Недалеко отсюда находится поместье Темного Когтя. Хотя лорд Темный Коготь не совсем наш союзник, известно, что он справедлив, для человека. Посмотри, сможет ли он взломать код на этом пергаменте.\n\nПоместье Темного Когтя находится в предгорьях за крепостью Дарнхольд.",
  },
  [26525] = {
    ["T"] = "Расшифровка Фелисити",
    ["O"] = "Дождитесь, пока Фелисити Перенольд расшифрует Заколдованный пергамент.",
    ["D"] = "Позволь мне представить Фелисити Перенольд, племянницу бывшего короля Айдена Перенольда и сестру Исидена Перенольда. Когда-то ее семья правила Альтеракскими горами, и она заинтересована в том, чтобы эта земля оставалась в безопасности от всех, кто стремится ее развратить и узурпировать.\n\nОна также чрезвычайно талантливый маг. Дай ей немного времени с пергаментом, и ты получишь ответы.",
