  [26730] = {
    ["T"] = "Подозрительное письмо",
    ["O"] = "Отнесите Подозрительное письмо профессору Старлингу в Восточные Чумные земли.",
    ["D"] = "Среди вещей Холодной Кости ты находишь наполовину законченное письмо, адресованное Расу Ледяному Шепоту. В нем говорится:\n\n«Рас, я получил уведомление о месте встречи и отправил курьера с предметом. Уверен ли ты, что встречаться так близко к Лордерону безопасно, да еще и после путешествия по территориям, контролируемым Синдикатом? Покров тьмы мало что значит для Отрекшихся. Если филактерия попадет в чужие руки, последствия...»\n\nПрофессор Старлинг заинтересуется этим предметом.",
  },
  [26731] = {
    ["T"] = "Полевая вылазка",
    ["O"] = "Ночью найдите место встречи для передачи и найдите место, чтобы понаблюдать за встречей.",
    ["D"] = "Лич никогда не побежден по-настоящему, пока вы не добудете и не очистите его филактерию. Филактерии Холодной Кости не было на его теле, и это письмо указывает, что ее куда-то унесли.\n\nСмотри — последняя запись в журнале говорит о том, что скоро состоится встреча с членом Королевского аптекарского общества в уединенном месте в тени Руин Лордерона! Инструкции в письме указывают, что нужно идти через Альтеракские горы, мимо Удела Дандреда и вдоль восточного края озера Лордамер.\n\nЭта встреча определенно должна быть сорвана — и произойти она должна ночью. Я останусь здесь и взломаю код, которым написана остальная часть журнала.",
