  [27259] = {
    ["T"] = "Припасы для Скрученного Шнура",
    ["O"] = "Отнесите ящик с припасами Скрученного Шнура на аванпост Скрученного Шнура к юго-западу от Крепости Грозового Топора.",
    ["D"] = "В этих опасных землях мы, члены Альянса, должны протягивать руку помощи нашим союзникам. В этом духе мне нужно, чтобы ты отнес посылку в новое гномье поселение под названием Скрученный Шнур. Я получил весточку от их трактирщика, Тинифьюза, что у него заканчиваются запасы еды и напитков.\n\nСкрученный Шнур находится недалеко. Ты можешь найти его к юго-западу отсюда, за Крепостью Грозового Топора.",
  },
  [27260] = {
    ["T"] = "Умоляя о возвращении",
    ["O"] = "Соберите 4 штормовые эссенции у вихревых буреносцев к северо-востоку от Деревни Теневой Добычи.",
    ["D"] = "Мой дом и мое сердце находится во Внутренних землях, с племенем Бешеного Клыка, но я был изгнан за то, что обучал некоторых кузенов Пустокорых темной стороне Шаманизма. Я глубоко сожалею об этих поступках, и все, чего я хочу, — это наконец-то почувствовать под ногами траву, увидеть колышущиеся деревья и проводить ночи с семьей.\n\nЧтобы сделать это, я предлагаю вождю Бешеного Клыка тотем молнии великой силы, и я надеюсь, что ты поможешь мне в этом задании.\n\nК северо-востоку отсюда находятся Вихревые буреносцы, могущественные элементали воздуха, которые бродят по этим землям. В них заключена ярость, которую я могу направить в тотем. Собери ее и верни мне, пожалуйста.",
  },
  [27261] = {
    ["T"] = "Умоляя о возвращении",
    ["O"] = "Соберите 10 емкостных рогов у старых громовых ящеров по всей Пустоши.",
    ["D"] = "Мне нужно еще кое-что, чтобы сделать тотем. По всей Пустоши ты найдешь старых громовых ящеров — самых старых, сильных и с самыми большими рогами. С энергией, которая текла через них за эти годы, я смогу создать мощный тотем молнии в подарок вождю. Не можешь ли ты собрать для меня несколько?",
  },
  [27262] = {
    ["T"] = "Самое свежее масло",
    ["O"] = "Соберите 7 кусков ворвани косатки для Марвина Уиллоувилла на побережье Деревни Теневой Добычи.",
    ["D"] = "Лучшее масло для фонарей и взрывчатки получается из ворвани косатки на берегах Пустошей. И таурены, и тролли отказываются помогать мне добывать их ворвань — какой-то ритуальное уважение к животным. Поэтому мне нужен такой отважный искатель приключений, как ты, чтобы испачкать руки за меня! Не мог бы ты войти в бухту и собрать для меня ворвань?",
  },
  [27263] = {
    ["T"] = "Величайшая доброта",
    ["O"] = "Убейте 8 умирающих кодо на Кладбище кодо.",
    ["D"] = "До конца не известно, почему кодо в Калимдоре так отчаянно пытаются добраться до кладбища, когда чувствуют, что их долгая жизнь подходит к концу, но их путешествие так же предсказуемо, как восход солнца.\n\nОднако некоторые кодо тяжело больны и бродят по земле в агонии, не в силах перейти в объятия Матери-Земли.\n\nСамое доброе, что мы можем сделать, — это направить их к ней. Ты сделаешь это для меня?",
  },
  [27264] = {
    ["T"] = "Разыскивается: Кейко",
    ["O"] = "Найдите и убейте Кейко в бухте за пределами Деревни Теневой Добычи в Пустошах.",
    ["D"] = "Рыбалка является важной частью пропитания этой деревни, но в бухте появился большой кит, которого мы назвали Кейко, который переворачивает наши рыбацкие лодки и калечит тауренов и троллей. Этого жестокого кита нужно убить, чтобы мы могли и дальше кормить как можно больше людей.\n\nПринесите доказательство смерти Кейко Джинар'Зиллену в Деревне Теневой Добычи.",
  },
  [27265] = {
    ["T"] = "Разыскивается: Уилфиз Серебряный",
    ["O"] = "Найдите и убейте Уилфиза Серебряного к северу от Ковена Маннорока в Пустошах.",
    ["D"] = "Мой бывший ученик сбежал, чтобы помогать Пылающему Легиону, забрав с собой ценные знания о наших планах здесь. Эта наглость не должна остаться безнаказанной! Я хочу, чтобы его голова была доставлена мне — на колу, если потребуется! Его последний раз видели собирающим грибы чуть севернее Ковена Маннорока.\n\n-- Иму Медная Сказка",
  },
  [27266] = {
    ["T"] = "Прикосновение молнии",
    ["O"] = "Поглотите 5 эссенций молний в жезл Джо'гона и вернитесь к Джо'гону в Клык Раздора.",
    ["D"] = "Приветствую, мон. Мне понадобится твоя помощь, если у тебя есть время. Я практикую свои шаманские навыки и хочу научиться манипулировать предметами. Для этого мне нужна эссенция молнии.\n\nЛучшее место для ее поиска — Громовой Хребет. Возьми мой жезл и используй его на зверях. Шкуры ящеров богаты молниями, и этот жезл поглотит ее.",
  },
  [27267] = {
    ["T"] = "Деревня в беде",
    ["O"] = "Соберите 5 чертополоха, 3 флакона крови охотника на скверну и 3 когтя Кровавого Когтя для Гароки на Поле Испытаний.",
    ["D"] = "Приветствую, мон. Я получил донесение от местной деревни о том, что они нуждаются в некоторых припасах. Если ищешь работу, помощь будет оценена.\n\nВ донесении говорилось, что им нужен чертополох, который можно найти разбросанным по долине. Затем кровь охотников на скверну в пещере к северу отсюда. Наконец, им нужны когти с колонии рапторов к югу отсюда.",
  },
  [27268] = {
    ["T"] = "Доставка Ворналу",
    ["O"] = "Доставьте ящик с реагентами мастеру Ворналу в деревню Сен'джин.",
    ["D"] = "Твоя помощь была очень кстати, мон. Как думаешь, когда будешь выходить из долины, не мог бы ты доставить эти реагенты?\n\nОни предназначены мастеру Ворналу в деревне Сен'джин, которую ты можешь найти к юго-востоку после выхода из долины. Понятия не имею, зачем они им нужны, но если ты их доставишь, у них может найтись для тебя еще работа.",
  },
  [27269] = {
    ["T"] = "Мастерство верховой езды на рапторе",
    ["O"] = "Изучите умение «Мастерство» у Ксар'Ти, затем поговорите с Зжолниром в Дуротаре, чтобы получить своего раптора.",
    ["D"] = "С возвращением. Ты пришел учиться мастерству верховой езды, правильно? Как и раньше, стоимость твоего раптора уже оплачена, но тебе придется заплатить за обучение. Быстрая езда — удовольствие дорогое, должен признать.\n\nПоговори с Зжолниром рядом со мной после того, как приобретешь навык. Он заведует продажей наших рапторов. Если у тебя еще нет денег, ты можешь вернуться позже.",
  },
  [27270] = {
    ["T"] = "Верховая езда на рапторе",
    ["O"] = "Изучите умение «Подготовка» у Ксар'Ти, затем поговорите с Зжолниром в Дуротаре, чтобы получить своего раптора.",
    ["D"] = "Итак, ты пришел за раптором, да? Так уж вышло, что я тебя ждал! Один таинственный благодетель оставил нам оплату за обычного раптора, и она адресована тебе лично, $N. Однако за обучение он не заплатил, так что, боюсь, тебе все равно придется его оплатить.\n\nПоговори с Зжолниром рядом со мной после того, как приобретешь навык. Он заведует продажей наших рапторов. Если у тебя еще нет денег, ты можешь вернуться позже.",
  },
  [27271] = {
    ["T"] = "Мастерство верховой езды на волке",
    ["O"] = "Изучите умение «Мастерство» у Кильдар, затем поговорите с Огунаро Волчьим Бегуном в Оргриммаре, чтобы получить своего ездового волка.",
    ["D"] = "С возвращением. Ты пришел учиться мастерству верховой езды, правильно? Как и раньше, стоимость твоего волка уже оплачена, но тебе придется заплатить за обучение. Быстрая езда — удовольствие дорогое, должен сказать.\n\nПоговори с Огунаро Волчьим Бегуном рядом со мной после того, как приобретешь навык. Он заведует продажей наших волков. Если у тебя еще нет денег, ты можешь вернуться в любое время.",
  },
  [27272] = {
    ["T"] = "Верховая езда на волке",
    ["O"] = "Изучите умение «Подготовка» у Кильдар, затем поговорите с Огунаро Волчьим Бегуном в Оргриммаре, чтобы получить своего ездового волка.",
    ["D"] = "Итак, ты пришел за волком, да? Так уж вышло, что я тебя ждал! Один таинственный благодетель оставил нам оплату за ездового волка, и она адресована тебе лично, $N. Однако за обучение он не заплатил, так что, боюсь, тебе все равно придется его оплатить.\n\nПоговори с Огунаро Волчьим Бегуном рядом со мной после того, как приобретешь навык. Он заведует продажей наших волков. Если у тебя еще нет денег, ты можешь вернуться позже.",
