  [27399] = {
    ["T"] = "Охота в безмятежности",
    ["O"] = "Соберите 10 шкур скакунов у оленей вокруг рощи Стоналог и вернитесь к охотнице Кайане в горах Стоналог.",
    ["D"] = "Приветствую, $C. Знакома ли ты с искусством охоты? Олени здесь, в роще, довольно неуловимы и станут серьезным испытанием для любого, кто захочет на них поохотиться. Их быстрые ноги и острые чувства делают их хорошей добычей.\n\nВот что я тебе скажу: если ты принесешь мне немного их меха, я даже сделаю тебе из него хороший плащ! Конечно, немного я оставлю и себе, потому что зимы здесь холодные! Удачи, и если ты не сможешь найти их здесь, олени иногда забредают немного дальше на юг, к тропе, ведущей в рощу.",
  },
  [27400] = {
    ["T"] = "Наручи Миркфаллона",
    ["O"] = "Соберите 8 наручей Миркфаллона у водных элементалей на озере Миркфаллон и вернитесь к Тамме Ветрокрылой в Убежище Солнечного Камня в горах Стоналог.",
    ["D"] = "Приветствую, $N. Приятно видеть здесь $C, ведь здесь много работы. Я живу в Убежище Солнечного Камня много лет, и эти горы никогда не перестают меня удивлять. Недавно на соседнем озере Миркфаллон пробудился магический источник, и мне нужна твоя помощь, чтобы с ним разобраться.\n\nОзеро — древнее и старое убежище для лесных созданий. Из-за источника из глубин озера вырвались водные элементали и вредят всем созданиям вокруг озера. Я хочу, чтобы ты избавился от водных элементалей и принес мне их наручи в доказательство своего поступка.",
  },
  [27401] = {
    ["T"] = "Озеро Миркфаллон",
    ["O"] = "Соберите 8 эссенций Миркфаллона у водных элементалей на озере Миркфаллон и вернитесь к Сентрике Песне Ночи в роще Стоналог в горах Стоналог.",
    ["D"] = "Горы Стоналог являются домом для многих драгоценных созданий Элуны, $N. Я пришла сюда, чтобы изучать их и заниматься алхимией в покое.\n\nЯ заметила к югу отсюда, на озере Миркфаллон, несколько водных элементалей. Мне очень хотелось бы проверить воздействие их эссенций. Не думаешь ли ты, что мог бы принести мне немного?\n\nПросто следуй по дороге на юг из рощи, и ты без проблем доберешься до озера Миркфаллон. Если ты принесешь мне пригодные для использования образцы, я с удовольствием отдам тебе немного своих зелий!",
  },
  [27402] = {
    ["T"] = "Руда для Солнечного Камня",
    ["O"] = "Добудьте 8 палладиевой руды в шахте Ветрокрыла и вернитесь к Гравналу в Убежище Солнечного Камня.",
    ["D"] = "Возможно, это не заметно, но у нас заканчиваются металлы, которые можно перековать в оружие для стражей. Если мы не сможем защитить себя, то оставим себя открытыми для атаки Альянса!\n\nЯ слышал, что компания Venture Co. нашла здесь, в Стоналоге, новую руду, которая, как говорят, прочнее железа, которое мы использовали. Я хочу, чтобы ты взял мою кирку и отправился в шахту Ветрокрыла. Просто войди в Утес Ветрокрыла и поверни направо, к краю горы, чтобы найти шахту. Если найдешь какую-нибудь особую руду, используй мою кирку, чтобы собрать ее, и принеси мне для изучения.",
  },
  [27403] = {
    ["T"] = "Раскаты земли",
    ["O"] = "Соберите 3 металлических шипа на хвосте у Прайдвингских небесных охотников, консортов или патриархов.",
    ["D"] = "Что ж, не могу отрицать, что мой брат сэкономил мне время на сборке этой штуковины, но этой штуке нужно одно: больше энергии! Я могу сделать из этого суперзарядное устройство с самодельной батареей, но мне понадобятся кое-какие вещи. Первое — это металлические хвосты самых сильных Прайдвингов, которых ты сможешь найти, которые находятся к северо-западу отсюда.\n\nЯ хочу только самых больших, злых и крепких из них! Ты можешь получить хороший взрослый хвост у Небесных охотников, Консортов или Патриархов.",
  },
  [27404] = {
