  [27927] = {
    ["T"] = "Воспоминания о чести и крови",
    ["O"] = "Поговорите с Эйтриггом о желании узнать больше о людях.",
    ["D"] = "Я слышал слух, что ты заинтересован в изучении нашего главного врага — людей. Учитывая сохраняющуюся напряженность между нашими народами, это кажется мудрым выбором — знай своего врага и все такое.\n\nМногие члены Орды сражались против людей в войнах, но никто не знает их умы так, как Тралл и Эйтригг. Тралл сейчас очень занят, но ты, возможно, сможешь добиться аудиенции с Эйтриггом. Разыщи его в Тронном зале Тралла в Оргриммаре.",
  },
  [27928] = {
    ["T"] = "Воспоминания о чести и крови",
