  [27961] = {
    ["T"] = "Фестиваль Копьеносцев",
    ["O"] = "Поговорите с посланником Вал'Кроном в Долине Духов в Оргриммаре.",
    ["D"] = "Волнующие новости! Затворнические тролли Копьеносцев из Темных Берегов проводят фестиваль, и впервые за всю историю они приглашают посторонних наблюдать и участвовать в их обычаях. Это редкая возможность понаблюдать за троллями, не рискуя получить топором по голове.\n\nЕсли тебе интересно, ты можешь найти их посланника в Долине Духов в Оргриммаре.",
