  [27962] = {
    ["T"] = "Фестиваль Копьеносцев",
    ["O"] = "Участвуйте в фестивале Копьеносцев, соревнуясь в метании топоров, затем вернитесь к Уне Джи'ро в деревню Копьеносцев.",
    ["D"] = "Добро пожаловать на фестиваль Копьеносцев, $R! Наше уединенное жилище редко принимает чужаков, так что чувствуй себя польщенным. Когда захочешь вернуться домой, просто поговори со мной.\n\nПрежде чем уйти, присоединись к вечеринке. Попробуй еду и выпивку — или, если ты смелый, может быть, потанцуй под светом, или даже испытай свои силы против чемпиона Копьеносцев Бру Занила в метании топоров. Ты найдешь все это дальше в деревне.",
  },
  [27963] = {
    ["T"] = "Основы берсеркинга",
    ["O"] = "Соберите компоненты вуду и принесите их ведьме Хал'де на фестиваль Копьеносцев.",
    ["D"] = "Ах, дитя, ты очередная жертва соревнований Бру, я вижу. Хал'де может дать тебе преимущество, необходимое, чтобы победить Бру — этого парня нужно сбить с его ветки.\n\nСекрет чемпионства Бру — в его глубокой связи с внутренней яростью, которая питает всех героев. Тролли учатся этой связи с рождения, но даже такой посторонний, как ты, может овладеть ею с должной практикой.\n\nЧтобы тебе было легче, мне нужно, чтобы ты принес несколько вещей — флакон моджо от троллей джунглей, немного зубов медведей из Зимнего Ключа, чтобы представить ледяных троллей, и кости наших врагов, лесных троллей. Подойдут и тролли Мохошкурых в руинах Восточных Чумных земель.\n\nТы можешь поговорить с Уной Джи'ро и посланниками в твоей столице, чтобы путешествовать туда и обратно между твоим домом и нашим.",
  },
  [27964] = {
    ["T"] = "Основы берсеркинга",
    ["O"] = "Победите Фетиш Копьеносцев в пещере в деревне Копьеносцев, находясь под действием баффа «Берсерк», затем вернитесь к ведьме Хал'де.",
    ["D"] = "Честно говоря, я не думал, что ты вернешься, $R. Ты крепче, чем выглядишь.\n\nЭто хорошо, потому что следующий шаг испытает тебя на прочность. Дальше по дороге есть пещера. Надень это ожерелье, которое я сделал из собранных тобой компонентов, и используй его, чтобы наделить тебя скоростью берсерка. Не борись с этим, отдайся этому. И позволь этой силе помочь тебе победить то, что ты найдешь в сундуке там, — если у тебя хватит смелости его открыть.",
