  [27972] = {
    ["T"] = "Обряд Мастерской",
    ["O"] = "Поговорите с Дж.Д. Колли в Убежище Маршала в кратере Ун'Горо.",
    ["D"] = "Теперь, когда у меня есть мой блокнот, я могу освежить в памяти то, что нашел. О, да! Я получил очень изношенное письмо от одного коллеги, который отправился в экспедицию в неизведанную землю кратера Ун'Горо. Она подозревала, что в Кратере могут быть остатки Титановой технологии, которые могут быть связаны с Подстраховкой.\n\nЗнаешь что, мне потребуется некоторое время, чтобы перечитать все свои заметки. Почему бы тебе не пойти по ее следам? Узнай новости прямо из уст гнома, так сказать. Это далекое путешествие, так что к твоему возвращению я должен быть готов продолжить с того места, на котором остановился.",
  },
  [27973] = {
    ["T"] = "Обряд Мастерской",
    ["O"] = "Убейте смоляных элементалей в кратере Ун'Горо, чтобы получить кусок Титановой технологии, и принесите его Дж.Д. Колли в Убежище Маршала в кратере Ун'Горо.",
    ["D"] = "Хоуи отправил тебя сюда лично, чтобы спросить о Титановой технологии? Ну, я не могу сказать ему много! Я исследовала кристаллические колоннады, разбросанные по кратеру, но не знаю наверняка, настолько ли они древние, как Титаны.\n\nЕсли бы я должна была гадать, элементали здесь очень стары. И вокруг полно смоляных ям. Может быть, что-то из их технологий было всосано смоляными элементалями? Если ты разделаешь достаточно много из них, возможно, ты найдешь какие-то старые титановые штуки!",
  },
  [27974] = {
    ["T"] = "Обряд Мастерской",
    ["O"] = "Дж.Д. Колли в Убежище Маршала в кратере Ун'Горо хочет, чтобы вы создали Изящный арканитовый конвертер и принесли его ей.",
    ["D"] = "Эта штука определенно открывается! Просто она запечатана механически. Если бы у нас только был Изящный арканитовый конвертер.\n\nПодожди! Ты сказал, что ты инженер, да? Ты можешь его сделать? Если ты сможешь сделать его и принести мне, я думаю, я смогу открыть эту штуку!",
  },
  [27975] = {
    ["T"] = "Обряд Мастерской",
    ["O"] = "Убейте землероев, беспилотных, туннельных рабочих и рабочих в любом улье в Силитусе, пока не найдете Странный древний объект, затем отнесите его Хоуи Картспрокету в Родник в Бесплодных землях.",
    ["D"] = "Это устройство внутри сферы...\n\n<Дж.Д. кашляет и вытряхивает из объекта больше песка.>\n\nОпределенно выглядит как Титановая технология. Но весь этот песок! Это не из Ун'Горо! И определенно не похоже на песок Танариса.\n\nНо... мимо нас недавно проходила исследовательская экспедиция, направлявшаяся в пустыню Силитус. Они сообщили, что нашли кучу жуков, роющихся в пустыне. Может быть, у роющих жуков будет больше таких объектов, если они оттуда?\n\nЭкспедиция нашла тропу вверх по холмам на северо-западе. Стоит попробовать. Если ты что-то найдешь, можешь отнести это Хоуи. Я бы не знала, что с этим делать.\n\nУдачи!",
  },
  [27976] = {
    ["T"] = "Обряд Мастерской",
    ["O"] = "Хоуи Картспрокет хочет, чтобы вы, используя свои инженерные навыки, создали для него 1 Полевого ремонтного бота, 3 Мастерских учебных манекена, 1 Мощный морской заряд и 20 ториевых гранат. Принесите их ему в Родник в Бесплодных землях.",
    ["D"] = "Ульдум — это древний исследовательский комплекс Титанов. Эти узлы — своего рода справочные книги, и устройство для их чтения должно существовать в комплексе. Но оно заперто наглухо.\n\nВозможно, этот узел поможет в наших исследованиях по открытию Ульдума. Я должен отправиться туда, как только закончу свою работу в Роднике.\n\nПрежде чем уйти, я должен быть готов к настоящему кемпингу в пустыне — и я слышал, что Танарис даже более удален, чем Бесплодные земли! Вот почему ты мой помощник! Мне понадобятся припасы: Полевой ремонтный бот и Мощный морской заряд для земляных работ, несколько Мастерских учебных манекенов для ловушек и куча ториевых гранат, чтобы отпугивать местную дикую природу!",
  },
