  [28027] = {
    ["T"] = "Обряд Глубин",
    ["O"] = "Используйте Экзотическую приманку для силитидов, чтобы рыбачить с Натом Пэйглом, и посмотрите, что вы поймаете!",
    ["D"] = "Ну, я не могу дождаться, чтобы попробовать эту наживку. Дай мне просто насадить ее на приманку и скажи, когда будешь готов. Кто знает, что мы поймаем?",
  },
  [28028] = {
    ["T"] = "Обряд Полей",
    ["O"] = "Поговорите с Дендритом Звездным Всполохом в Ночной Гавани в Луносвете.",
    ["D"] = "Ну вот, ты действительно отточил свое мастерство травничества, не так ли? Нечасто заходит кто-то с твоим талантом.\n\nНа самом деле, я хотел бы попросить об услуге. У меня есть друг в Луносвете, который изучает влияние порчи на растения. Он устал путешествовать между Проклятым лесом и Чумными землями и мог бы использовать помощника. Если заинтересован, отправляйся в Ночную Гавань и поговори с Дендритом Звездным Всполохом.\n\nЕсли ты никогда не был в Луносвете, ну, тебе придется пройти через территорию фурболгов Древесной Лапы в Проклятом лесу, чтобы добраться туда. Фурболги не слишком дружелюбны к незнакомцам, но я уверен, ты сможешь понять, как пройти.",
  },
  [28029] = {
    ["T"] = "Обряд Полей",
    ["O"] = "Дендрит Звездный Всполох хочет, чтобы вы, используя свой навык травничества, собрали 20 горного серебрянника и 20 ледяного покрова и принесли их ему в Ночную Гавань в Луносвете.",
    ["D"] = "Ты заинтересован в помощи с моими исследованиями? Превосходно. Мне многое нужно сделать, и у меня больше нет всего времени в мире.\n\nЯ ценю твою готовность, но должен оценить твои навыки. Покажи мне свои способности в травничестве, собрав горной серебрянник и ледяной покров. Тогда я буду знать, что у тебя есть талант, необходимый для выполнения предстоящих задач.",
