  [28050] = {
    ["T"] = "Обряд Диких земель",
    ["O"] = "Принесите черную драконью чешую, синюю драконью чешую, зеленую драконью чешую и красную драконью чешую Хемету Несингвари в экспедицию Несингвари в Тернистой долине.",
    ["D"] = "Я не могу доверить эту работу любому сдирателю шкур, $N, так что мне нужно, чтобы ты подтвердил свои полномочия.\n\nЯ охотился на самых опасных зверей в Азероте, и самые хитрые из них — драконы. Тебе не нужно охотиться на драконов, но тебе нужно освежевать нескольких и принести мне их драконью чешую в подтверждение того, что ты знаешь толк в сдирании шкур. Мне нужно по одной от черных, синих, зеленых и красных драконов.",
  },
  [28051] = {
    ["T"] = "Обряд Диких земель",
    ["O"] = "Хемет Несингвари хочет, чтобы вы, используя свой навык сдирания шкур, собрали 6 сверхпрочных шкур морозного саблезуба у саблезубов в Зимнем Ключе и принесли их ему в его лагерь в Тернистой долине.",
    ["D"] = "У меня есть клиент, который желает сохранить свою анонимность, пока он покупает несколько премиальных товаров, связанных со зверями. Думаю, есть некоторая обеспокоенность по поводу конкуренции, если личность будет раскрыта.\n\nПервое, что меня попросили собрать, — это премиальная шкура морозного саблезуба из Зимнего Ключа. Не какая-нибудь шкура подойдет. Покупатель хочет только самую толстую и теплую. Думаешь, ты справишься с этим? Это самое легкое из всего.",
  },
  [28052] = {
