  [31017] = {
    ["T"] = "Требования для ритуала",
    ["O"] = "Лорду Максвеллу Тирозу в Часовне Света нужно несколько материалов, чтобы очистить скипетр:\n- Флакон святой воды из Стратхольма.\n- Один слиток арканита от знающего алхимика или шахтера.\n- Три священные свечи, можно купить у торговца реагентами.\n- Три кучки пыли душ от заклинателя.\n- Один символ божественности, также можно купить у торговца реагентами.",
    ["D"] = "Я вижу вашу опасность, $r. Осквернить дух дракона магией некроманта — темное дело. Если я могу чем-то помочь, я помогу.\n\n<Максвелл тратит несколько минут, планируя ритуал.>\n\nМне понадобится несколько ингредиентов и материалов:\n\nСначала нам нужна основа, которая будет служить вместилищем для скипетра. Арканит для этого подходит лучше всего, поэтому нам понадобится хотя бы один слиток. Снаружи ритуального круга нужно будет разместить три священные свечи на трех кучках пыли душ. Самыми важными частями будут символ божественности, действующий как магический усилитель, и флакон святой воды из Стратхольма, чтобы окропить скипетр.\n\nВозвращайся, когда добудешь все это. Жаль, что в часовне нет торговца реагентами... Я буду ждать.",
  },
  [31018] = {
    ["T"] = "Священная концентрация",
    ["O"] = "Дождитесь завершения ритуала очищения.",
    ["D"] = "",
  },
  [31019] = {
    ["T"] = "Обратный путь",
    ["O"] = "С очищенным скипетром мы можем вернуться в Зимний Ключ. Талрук из Лазурного Покоя будет ждать нас.",
    ["D"] = "<Лорд Максвелл Тироз заметно запыхался.>\n\nРитуал оказался более изнурительным, чем я ожидал.\n\nЯ сделал все, что мог... но я не знаю, увенчается ли ваш план успехом. Вернись к останкам дракона в Лазурный Покой. Если теперь направить скипетр на его череп, это должно призвать дух дракона и позволить вам поговорить.\n\nПрощай, $c, и удачи. Уничтожь скипетр после того, как все будет сделано. Этой магии не должно быть позволено существовать.",
  },
  [31020] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Используйте скипетр на черепе в Лазурном Покое и поговорите с духом дракона.",
    ["D"] = "Лорд Максвелл сказал, что нужно направить энергию скипетра в череп дракона. Если все пойдет по плану, мы призовем дух павшего синего дракона. Надеюсь, у него будут ответы и решения, которые нам так отчаянно нужны.",
  },
  [31021] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Поговорите с Велигосом в Лазурном Покое. Узнайте его историю и обсудите дальнейшие действия.",
    ["D"] = "<Дух, кажется, медленно стабилизируется и приходит в сознание.>\n\nЯ Велигос, мастер тайной магии и защитник магии.\n\n<Велигос сосредотачивает внимание на кристалле.>\n\nПочему эта проклятая штука активна? Кто был настолько глуп, чтобы снять мои чары?\n\nГовори, $r, ты причина этого надвигающегося бедствия?",
  },
  [31022] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Велигос попросил нас пробиться вглубь пещеры Лазурного Покоя и убить огров, которые питают кристалл энергией.",
    ["D"] = "Эти дураки из Черной горы, должно быть, нашли мою сферу и снова собрали ее... или каким-то образом воспроизвели ее магию. Несомненно, надеясь питаться от кристалла.\n\nТот, кто это сделал, должно быть, очень могуществен и владеет самой коварной магией. Я не чувствую здесь такого присутствия, но здесь что-то есть.\n\nВ той пещере у края горы проводится ритуал. Убей того, кто направляет эти чары, это должно замедлить работу кристалла и купить нам немного времени.",
  },
  [31023] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Поговорите с Велигосом, когда будете готовы начать призыв. Он хочет, чтобы мы убили Мага Лорда Камня Шпиля у кристалла в Лазурном Покое.",
    ["D"] = "В этой форме мои способности сильно ограничены, но я пытался заглянуть в поток магии внутри кристалла. Мне удалось найти следы энергии моей сферы, а также того, кто, вероятно, владел ею.\n\n<Вы чувствуете, как энергия вокруг Велигоса возрастает.>\n\nЯ должен быть в состоянии притащить его сюда через портал. Дай мне знать, когда будешь готов, $N.",
  },
  [31024] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Велигос из Лазурного Покоя хочет, чтобы мы спустились в глубины Нижней Черной горы, призвали и убили истинного предводителя клана Камня Шпиля — Урока Ужасного Воя, и забрали вторую часть его сферы контроля.",
    ["D"] = "Теперь, когда одна часть сферы найдена, нужно выследить другую.\n\n<Велигос направляет свою магию в осколок, и он начинает резонировать с чем-то.>\n\nСобери своих союзников, $r, отправляйся в Черную гору и убей Урока Ужасного Воя. Я чувствую, что он прячется за магической вуалью. Сломай его последователей, вытащи его из тени, брось вызов его правлению и избавь мир от его темного влияния.\n\nПринеси мне последнюю часть моей сферы контроля. Теперь я сосредоточусь на накоплении сил для того, что грядет.",
  },
  [31025] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Велигосу из Лазурного Покоя нужно несколько реагентов, чтобы создать магические барьеры, которые подавят скверну:\n\n- Люменкамень, антимагический металл, можно найти в Мертвом ущелье, у башни Каразхана.\n- Четыре куска Камня стража у каменных стражей в кратере Ун'Горо.\n- Две грубые шкуры от искусного кожевника.\n- Два куска луноткани от портного.\n- Два зелья антимагии от алхимика.",
    ["D"] = "<Из кристалла слышен слышимый звук, и от него исходит ужасный жар. Такое чувство, будто саму вашу сущность втягивают внутрь.>\n\nУ нас заканчивается время, $n. Я перебрал в уме бесчисленные возможные решения, и, возможно, есть выход... Сфера повреждена безвозвратно, ни один ремесленник в Азероте не достаточно искусен, чтобы починить ее. Но это не значит, что она бесполезна. Я, возможно, знаю, как ограм удалось пробудить кристалл. Это далеко от изящества, но сработает.\n\nПока я буду готовиться к этому, тебе снова придется отправиться в мир. Мы должны создать антимагические барьеры, которые остановят распространение этой магической скверны. После того, как кристалл стабилизируется, эти барьеры обеспечат, что сдерживание останется навсегда.\n\nОтправляйся в Мертвое ущелье. В подвалах башни Медива ты найдешь Люменкамень — редкий металл, который обладает свойством нейтрализовать магию. Но будь осторожен: туннели и пещеры там коварны и полны истерзанных призраков и нежити.\n\nЗатем отправляйся в кратер Ун'Горо. Там бродят защитники земли — покрытые рунами големы огромной силы. Собери их камни стражей, они послужат ядром для барьеров.\n\nЧтобы защитить барьеры от воздействия стихий, обратись за помощью к искусным ремесленникам. Добудь две грубые шкуры и два куска ткани, пропитанной энергией лунного колодца. Их нужно будет вымочить в антимагической смеси.",
  },
  [31026] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Дождитесь, пока Велигос закончит накладывать заклинание призыва.",
    ["D"] = "Я сейчас начну накладывать заклинание. Отойди и дай мне сосредоточиться.",
  },
  [31027] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Начните очищение Лазурного Покоя в Зимнем Ключе. Разместите четыре подавляющих барьера на каждом участке земли, пораженном магической скверной.",
    ["D"] = "Барьеры готовы. Размести их в центре пораженных земель.\n\nОстерегайся огров, они, кажется, все еще охотятся за нами.",
  },
  [31028] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Пришло время положить этому конец. Поднесите сферу Велигоса к кристаллу в Лазурном Покое и начните подавление.",
    ["D"] = "Я сделал все возможное, чтобы временно соединить сферу, но я слишком слаб, чтобы управлять ею.\n\nПоднеси сферу к кристаллу, я волью остатки своих сил в обе части и попытаюсь их гармонизировать.\n\nВ этом деле огромная энергия кристалла сыграет ключевую роль в его собственном подавлении. Я обрушу поток магии в себя, и мы избавим Азерот от этого бедствия.\n\n<Велигос делает паузу.>\n\nКак бы мне хотелось изучить его... если бы только я преуспел много лет назад... Возможно, в другой жизни...",
  },
  [31029] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Поговорите с Велигосом, чтобы уничтожить Скипетр Вектуса и освободить его дух. После этого мы должны дать знать Талруку обо всем, что произошло. Его можно найти в Лазурном Покое в Зимнем Ключе.",
    ["D"] = "Теперь, когда кристалл успокоен, энергии, на которых я поддерживал свое существование, иссякают.\n\n$N, прости, что я подвел всех много лет назад. Мое любопытство едва не привело к бесчисленным смертям. Пожалуйста, принеси эту памятку моему выводку, пусть они узнают мою историю, пусть предостерегут своих детенышей.\n\nТеперь осталось только сломать скипетр некроманта.\n\n<Велигос на мгновение зависает, долго вглядываясь в море внизу.>\n\nМой долг выполнен, пора уходить. Я готов.",
  },
  [31030] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Отнесите Памятку Велигоса прародительнице-покровительнице Халех. Ее можно найти в Мазториле в Зимнем Ключе.",
    ["D"] = "Ты хорошо справился, $N. Ты должен почтить просьбу дракона и отнести его памятку матриарху Мазторила. Это трагическая история, и она должна быть известна.\n\nВсякий раз, когда ты почувствуешь себя потерянным, возвращайся в это место. Оно было причиной великой скорби, но со временем в него вернется безмятежность.\n\nПрощай, $r.",
  },
  [31031] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Вернитесь в Оргриммар и сообщите Траллу о вашем успехе.",
    ["D"] = "Спасибо тебе еще раз, искатель приключений. Сегодня ты совершил великое дело для Азерота.\n\nНесомненно, твои лидеры захотят услышать о твоих подвигах.",
  },
  [31032] = {
    ["T"] = "Магическая скверна",
    ["O"] = "Вернитесь в Стальгорн и сообщите королю Магни Бронзобороду о вашем успехе.",
    ["D"] = "Спасибо тебе еще раз, искатель приключений. Сегодня ты совершил великое дело для Азерота.\n\nНесомненно, твои лидеры захотят услышать о твоих подвигах.",
  },
  [31033] = {
    ["T"] = "Досадное препятствие",
    ["O"] = "Обыщите Мертвое ущелье в поисках того, кто может знать о демонах.",
    ["D"] = "Люменкамень нигде не найден, но вы замечаете табличку на одном из демонов. При ближайшем рассмотрении она выглядит написанной на непонятном демоническом языке:\n\nRikk alar il xi zennrakkan lok Kirasath Raka ruk asj xi veni parn kar lok revola rukadare il Karazhan. Lok kamil buras naztheros arakalada xi daz veni. Rikk lok parn il asj xi Z gular maladath lok buras kanrethad il lok kamil. Kiel ashjrethul ante buras gul revos. \nIl kirasath Vorakem Zekulrakkas Archim il Aman Veni Kazzak.\n\nНам понадобится помощь в расшифровке смысла этого послания. Судя по некоторым признакам, похоже, мы были не первыми людьми, недавно посетившими мастерскую. Возможно, они все еще находятся где-то в Мертвом ущелье, если нам повезет.\n\nС духами, ограми и теперь демонами, окружающими башню, где бы они могли прятаться?",
  },
  [31034] = {
    ["T"] = "Помощь, чтобы получить помощь",
    ["O"] = "Незнакомец из Мертвого ущелья — вероятно, наш лучший шанс найти Люменкамень, который забрали демоны. Нам нужно будет принести ему еду, восстанавливающую ману, и немного алкоголя.",
    ["D"] = "Я могу тебе помочь, это правда, но ты же знаешь, как это бывает... Сначала мне кое-что нужно от тебя.\n\nКак ты мог заметить, сейчас я не в лучшей форме. Спасаясь из подвала, я выжал свое тело далеко за пределы возможного.\n\nПомоги мне восстановить магию, и я помогу тебе. Что-то с продолжительным усилением восстановления моей маны и что-то, чтобы это запить, мне бы очень помогло. Пока тебя не будет, я начну переводить табличку.",
  },
  [31035] = {
    ["T"] = "Ключевая информация",
    ["O"] = "Поговорите с Каран'том Ардентисом в Мертвом ущелье.",
    ["D"] = "Мне уже лучше, спасибо, $c. Позволь представиться: я Каран'т Ардентис из Кирин Тора.\n\nДавай поговорим об этом.",
  },
  [31036] = {
    ["T"] = "Лобовая атака",
    ["O"] = "Найдите лагерь демонов и зачистите его. Люменкамень, который мы ищем, тоже должен быть где-то там.",
    ["D"] = "Демоны самоуверенны, и это их главная слабость, которую ты должен использовать. Лучшая ставка — застать их врасплох. Встреть их лицом к лицу и убей столько, сколько сможешь, в хаосе.\n\nОни принесли бы металл, который ты ищешь, в свой лагерь, ты, несомненно, найдешь его там.\n\nЯ бы пошел с тобой, но мое тело все еще слабо. Я предполагаю, что они что-то делали с металлом, и это было причиной того, что случилось со мной. Береги себя там, если почувствуешь что-то похожее на то, что я описал, — беги.",
  },
  [31037] = {
    ["T"] = "Чтобы отдать долг",
    ["O"] = "Маг Кирин Тора, которого мы встретили в Мертвом ущелье, пригласил нас навестить его в его лагере. Он сказал, что может помочь нам с мощными чарами. Это должно быть хорошо.",
    ["D"] = "Приветствую, $N!\n\nЯ рад сообщить, что чувствую себя лучше. Ты преуспел в своем задании?\n\nЯ скоро покину Мертвое ущелье. Загляни, когда сможешь. Думаю, у меня достаточно сил, чтобы отблагодарить тебя за всю оказанную помощь. Мои чары сильны, они, несомненно, помогут тебе в грядущих битвах.\n\nС уважением, Каран'т.",
  },
  [31038] = {
